1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const COMPONENT_TYPES = new Set(["rune"]);
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	const FIRST_INSURANCE_SURCHARGE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
33	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
34	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
35	
36	// A block applies only to a group of exactly BLOCK_SIZE alike components,
37	// priced at BLOCK_PREMIUM; any other count is priced individually.
38	const componentBasePremium = (count: number, perComponent: number): number => {
39	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
40	  return count * perComponent;
41	};
42	
43	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const countByType = (items: Item[]): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	  }
52	  return counts;
53	};
54	
55	const itemsBasePremium = (items: Item[]): number => {
56	  const mainItems = items.filter((item) => !isComponent(item));
57	  const componentCounts = countByType(items.filter(isComponent));
58	
59	  const mainItemsPremium = sum(mainItems.map((item) => BASE_PREMIUM[item.type]));
60	  const componentsPremium = sum(
61	    Object.entries(componentCounts).map(([type, count]) =>
62	      componentBasePremium(count, BASE_PREMIUM[type]),
63	    ),
64	  );
65	
66	  return mainItemsPremium + componentsPremium;
67	};
68	
69	const quotePremium = (items: Item[]): number => {
70	  const itemsPremium = itemsBasePremium(items) * (1 + FIRST_INSURANCE_SURCHARGE);
71	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
72	};
73	
74	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
75	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
76	  return { results };
77	};
